observacoes_negocio:
Concatenación de errores según la función : LAMBDA(fila,
      TEXTJOIN(", ", VERDADERO, SI(fila=1, CB$1:CH$1, ""))
    )

calculo_bq_to_be_original:
CASE WHEN fecha de facturacion < fecha de cierre
 WHEN Etapa <> {Calificar, Evaluación, Propuesta} 
THEN 1

calculo_bq_final:
CASE WHEN fecha de facturacion < fecha de cierre
 WHEN Etapa <> {Calificar, Evaluación, Propuesta} 
THEN 1

create_view_select_expr:
